/**
 * Intelligence Data Loader
 *
 * Central import point for all intelligence JSON files.
 * Validates data structure and provides safe defaults for
 * missing or malformed fields.
 *
 * Data generated by: scripts/fetch-nflverse-rosters.js
 * Run: npm run data:fetch
 */

import rawActive from './former_teammates_active.json';
import rawMatchups from './former_teammates_by_matchup.json';

// Validate and normalize — handle malformed data gracefully
function safeActive(data) {
  if (!data || typeof data !== 'object') return { edges: {}, meta: {} };
  return {
    edges: data.edges && typeof data.edges === 'object' ? data.edges : {},
    meta: data.meta && typeof data.meta === 'object' ? data.meta : {},
  };
}

function safeMatchups(data) {
  if (!data || typeof data !== 'object') return { matchups: {} };
  return {
    matchups: data.matchups && typeof data.matchups === 'object' ? data.matchups : {},
  };
}

export const formerTeammatesActive = safeActive(rawActive);
export const formerTeammatesByMatchup = safeMatchups(rawMatchups);

/**
 * Check what intelligence data is available
 */
export function getIntelligenceStatus() {
  const edgeCount = Object.keys(formerTeammatesActive.edges).length;
  const matchupCount = Object.keys(formerTeammatesByMatchup.matchups).length;
  return {
    formerTeammates: edgeCount > 0,
    matchupIndex: matchupCount > 0,
    edgeCount,
    matchupCount,
  };
}
